### _call() Method Structure

Multimodal pipelines typically follow this pattern:

**For simple image input pipelines (ImageToText):**
```javascript
async _call(images, generate_kwargs = {}) {
    const isBatched = Array.isArray(images);
    const preparedImages = await prepareImages(images);

    const { pixel_values } = await this.processor(preparedImages);

    const toReturn = [];
    for (const batch of pixel_values) {
        batch.dims = [1, ...batch.dims]
        const output = await this.model.generate({ inputs: batch, ...generate_kwargs });
        const decoded = this.tokenizer.batch_decode(output, {
            skip_special_tokens: true,
        }).map(x => ({ generated_text: x.trim() }))
        toReturn.push(decoded);
    }

    return isBatched ? toReturn : toReturn[0];
}
```

**For image + text input pipelines (ZeroShotImageClassification):**
```javascript
async _call(images, candidate_labels, {
    hypothesis_template = "This is a photo of {}"
} = {}) {
    const isBatched = Array.isArray(images);
    const preparedImages = await prepareImages(images);

    // Process text inputs
    const texts = candidate_labels.map(x => hypothesis_template.replace('{}', x));
    const text_inputs = this.tokenizer(texts, {
        padding: true,
        truncation: true,
    });

    // Process image inputs
    const { pixel_values } = await this.processor(preparedImages);

    // Run model with both text and image inputs
    const output = await this.model({ ...text_inputs, pixel_values });

    // Post-process results
    const toReturn = [];
    for (const batch of output.logits_per_image) {
        const probs = softmax(batch.data);
        const result = [...probs].map((x, i) => ({
            score: x,
            label: candidate_labels[i]
        }));
        result.sort((a, b) => b.score - a.score);
        toReturn.push(result);
    }

    return isBatched ? toReturn : toReturn[0];
