/**
 * Image-text-to-text pipeline using any `AutoModelForImageTextToText`. This pipeline generates
 * text given an image and a text prompt.
 *
 * **Example:** Chat with `HuggingFaceTB/SmolVLM-256M-Instruct` about an image.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'HuggingFaceTB/SmolVLM-256M-Instruct');
 * const messages = [
 *   {
 *     role: 'user',
 *     content: [
 *       { type: 'image', url: 'https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/bee.jpg' },
 *       { type: 'text', text: 'What do you see in this image?' },
 *     ],
 *   },
 * ];
 * const text = pipe.tokenizer.apply_chat_template(messages, {
 *   tokenize: false,
 *   add_generation_prompt: true,
 * });
 * const url = 'https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/bee.jpg';
 * const output = await pipe(url, text, { max_new_tokens: 200 });
 * // [{ generated_text: 'The image shows a bee ...' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(images, text, generate_kwargs = {}) {
        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        // Wrap scalar text in array to match processor expectations (one text per image)
        const texts = Array.isArray(text) ? text : [text];

        // Call processor with text-first convention (matches modern VLMs: Idefics3, SmolVLM, Qwen2VL)
        const inputs = await this.processor(texts, preparedImages);

        // Record input_ids length so we can strip the prompt from the output
        const promptLength = inputs.input_ids.dims.at(-1);

        // generate() finds `input_ids` via main_input_name; pixel_values and other
        // processor outputs flow through model_kwargs to the VLM forward pass
        const outputTokenIds = /** @type {Tensor} */ (await this.model.generate({
            ...inputs,
            ...generate_kwargs,
        }));

        // Decode and strip the prompt prefix from each output sequence
        const decoded = this.tokenizer.batch_decode(outputTokenIds, {
            skip_special_tokens: true,
        });

        // Decode the prompt tokens to know the character-length offset to strip
        const promptDecoded = this.tokenizer.batch_decode(inputs.input_ids, {
            skip_special_tokens: true,
        });

        const toReturn = [];
        for (let i = 0; i < decoded.length; ++i) {
            // For each sequence, strip the prompt portion by character length
            const promptText = promptDecoded[Math.floor(i / outputTokenIds.dims[0] * texts.length)];
            const generated = decoded[i].slice(promptText.length).trim();
            toReturn.push({ generated_text: generated });
        }

        // Non-batched: return a single array (matching ImageToTextPipeline convention)
        // Batched: return array of arrays (one per input image)
        if (isBatched) {
            // Re-group: outputTokenIds.dims[0] sequences for texts.length inputs
            const numReturnSeqs = outputTokenIds.dims[0] / texts.length;
            const grouped = [];
            for (let i = 0; i < texts.length; ++i) {
                grouped.push(toReturn.slice(i * numReturnSeqs, (i + 1) * numReturnSeqs));
            }
            return grouped;
        }
        return toReturn;
    }
}
```

**Key implementation notes:**

- `promptLength` is read but only used indirectly — we use `batch_decode` on both the output and the input `input_ids`, and then slice by character length. This matches exactly how `TextGenerationPipeline` strips the prompt when `return_full_text = false`.

- The batching regrouping logic: when batched with N images and `num_return_sequences=K`, `generate()` returns N*K output rows. We group them into N arrays of K elements each, matching the structure of `ImageToTextPipeline`.

- When `isBatched = false` we return a flat `[{generated_text: ...}]` array (not nested), which matches `ImageToTextPipeline`'s non-batched return of `toReturn[0]` where `toReturn[0]` was an array of decoded outputs.

