### Step 3 — Add `ImageTextToTextPipeline` class (after Step 2 typedefs)

Insert immediately after the typedef block from Step 2, still before the
`ImageClassificationSingle` typedef.

```javascript
/**
 * Image text to text pipeline using any `AutoModelForImageTextToText`. This pipeline generates
 * text from an image and a text prompt.
 *
 * **Example:** Generate text from an image with `HuggingFaceTB/SmolVLM-256M-Instruct`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'HuggingFaceTB/SmolVLM-256M-Instruct');
 * const url = 'https://huggingface.co/datasets/huggingface/documentation-images/resolve/main/bee.jpg';
 * const messages = [
 *   {
 *     role: 'user',
 *     content: [
 *       { type: 'image' },
 *       { type: 'text', text: 'Describe this image.' },
 *     ],
 *   },
 * ];
 * const text = pipe.tokenizer.apply_chat_template(messages, {
 *   tokenize: false,
 *   add_generation_prompt: true,
 * });
 * const output = await pipe(url, text, { max_new_tokens: 200 });
 * // [{ generated_text: 'The image shows a bee ...' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(images, text, generate_kwargs = {}) {
        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        // Normalize text to an array (one entry per image)
        const texts = Array.isArray(text) ? text : [text];

        // Call processor with text-first convention (Idefics3, SmolVLM, Qwen2-VL).
        // Note: processors for LLaVA, PaliGemma, and Florence2 use images-first
        // convention and are not directly compatible with this pipeline.
        const inputs = await this.processor(texts, preparedImages);

        // Generate output token sequences. `input_ids` is found in `inputs` and
        // matched via main_input_name; `pixel_values` and other processor outputs
        // flow through model_kwargs to the multimodal forward pass.
        const outputTokenIds = /** @type {Tensor} */ (await this.model.generate({
            ...inputs,
            ...generate_kwargs,
        }));

        // Decode the prompt tokens (image tokens are stripped as special tokens)
        // so we can determine the character-length offset to remove from the output.
        const promptDecoded = this.tokenizer.batch_decode(inputs.input_ids, {
            skip_special_tokens: true,
        });

        // Decode the full output (prompt tokens already stripped as special tokens)
        const decoded = this.tokenizer.batch_decode(outputTokenIds, {
            skip_special_tokens: true,
        });

        // Group outputs by input: for N inputs with K return sequences each,
        // outputTokenIds has N*K rows. Collect each group of K into one result array.
        const numReturnSeqs = outputTokenIds.dims[0] / texts.length;
        const toReturn = [];
        for (let i = 0; i < texts.length; ++i) {
            const group = [];
            for (let j = 0; j < numReturnSeqs; ++j) {
                const outputIdx = i * numReturnSeqs + j;
                group.push({
                    generated_text: decoded[outputIdx].slice(promptDecoded[i].length).trim(),
                });
            }
            toReturn.push(group);
        }

        // Non-batched: return the single result array directly (e.g. [{generated_text}])
        // Batched:     return an array of result arrays (one per input image)
        return isBatched ? toReturn : toReturn[0];
    }
}
```

