/**
 * @typedef {Object} ImageTextToTextSingle
 * @property {string} generated_text The generated text output for the given image and prompt.
 * @typedef {ImageTextToTextSingle[]} ImageTextToTextOutput
 *
 * @callback ImageTextToTextPipelineCallback Process an image and text prompt, generating text output.
 * @param {ImagePipelineInputs} images The input image(s) to process.
 * @param {string|string[]} text The text prompt(s) to use for generation. Must match the number of images.
 * @param {Partial<import('./generation/configuration_utils.js').GenerationConfig>} [generate_kwargs] Additional keyword arguments to pass along to the generate method of the model.
 * @returns {Promise<ImageTextToTextOutput|ImageTextToTextOutput[]>} An object (or array of objects) containing the generated text(s).
 *
 * @typedef {TextImagePipelineConstructorArgs & ImageTextToTextPipelineCallback & Disposable} ImageTextToTextPipelineType
 */

/**
 * Image-text-to-text pipeline using `AutoModelForImageTextToText`. This pipeline accepts an image
 * and a text prompt, processes both through a multimodal model, and returns generated text.
 *
 * **Note:** Processors that use image-first calling conventions (e.g., `LlavaProcessor`,
 * `PaliGemmaProcessor`, `Florence2Processor`) are not compatible with this pipeline, which
 * uses the text-first convention required by models such as Idefics3, SmolVLM, and Qwen2-VL.
 *
 * **Example:** Generate a response for an image and text prompt w/ `HuggingFaceTB/SmolVLM-256M-Instruct`.
 * ```javascript
 * const pipe = await pipeline('image-text-to-text', 'HuggingFaceTB/SmolVLM-256M-Instruct');
 * const url = 'https://huggingface.co/datasets/Xenova/transformers.js-docs/resolve/main/cats.jpg';
 * const output = await pipe(url, 'Describe this image.');
 * // [{ generated_text: 'Two cats are sitting on a couch.' }]
 * ```
 */
export class ImageTextToTextPipeline extends (/** @type {new (options: TextImagePipelineConstructorArgs) => ImageTextToTextPipelineType} */ (Pipeline)) {

    /**
     * Create a new ImageTextToTextPipeline.
     * @param {TextImagePipelineConstructorArgs} options An object used to instantiate the pipeline.
     */
    constructor(options) {
        super(options);
    }

    /** @type {ImageTextToTextPipelineCallback} */
    async _call(images, text, generate_kwargs = {}) {
        const isBatched = Array.isArray(images);
        const preparedImages = await prepareImages(images);

        // Normalize text to an array — one prompt per image
        const texts = Array.isArray(text) ? text : [text];

        // text-first processor convention (Idefics3 / SmolVLM / Qwen2-VL)
        const inputs = await this.processor(texts, preparedImages);

        const outputTokenIds = /** @type {import('./utils/tensor.js').Tensor} */ (await this.model.generate({
            ...inputs,
            ...generate_kwargs,
        }));

        // Strip the input prompt from each output by measuring the decoded prompt length
        const decoded = this.tokenizer.batch_decode(outputTokenIds, {
            skip_special_tokens: true,
        });

        const promptLengths = this.tokenizer.batch_decode(inputs.input_ids, {
            skip_special_tokens: true,
        }).map(x => x.length);

        /** @type {ImageTextToTextOutput[]} */
        const toReturn = Array.from({ length: preparedImages.length }, _ => []);
        for (let i = 0; i < decoded.length; ++i) {
            const imageIndex = Math.floor(i / outputTokenIds.dims[0] * preparedImages.length);
            toReturn[imageIndex].push({
                generated_text: decoded[i].slice(promptLengths[imageIndex]),
            });
        }

        return isBatched ? toReturn : toReturn[0];
    }
}

